class SecureStorage {
  static const _prefix = 'secure_payment_';
  final SharedPreferences prefs;

  SecureStorage._(this.prefs);

  static Future<SecureStorage> create() async {
    final prefs = await SharedPreferences.getInstance();
    return SecureStorage._(prefs);
  }

  Future<void> write(String key, String value) async {
    await prefs.setString('$_prefix$key', value);
  }

  String? read(String key) => prefs.getString('$_prefix$key');

  Future<void> delete(String key) async {
    await prefs.remove('$_prefix$key');
  }
}

class PaymentBackendApi {
  final PaymentConfig config;
  final http.Client _client;

  PaymentBackendApi(this.config, {http.Client? client}) : _client = client ?? http.Client();

  Uri _uri(String path) => Uri.parse('${config.backendBaseUrl}$path');

  Future<Map<String, dynamic>> _postJson(String path, Map<String, dynamic> body) async {
    final response = await _client
        .post(
          _uri(path),
          headers: const {'Content-Type': 'application/json'},
          body: jsonEncode(body),
        )
        .timeout(config.requestTimeout);

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        'Backend request failed (${response.statusCode})',
        responseBody: response.body,
      );
    }

    final decoded = jsonDecode(response.body);
    if (decoded is Map<String, dynamic>) return decoded;
    throw PaymentException('Invalid backend response');
  }

