    required String userId,
    required String productId,
    required String transactionId,
    required String receiptData,
    required bool isSandbox,
  }) {
    return _postJson('/payments/iap/verify', {
      'userId': userId,
      'productId': productId,
      'transactionId': transactionId,
      'receiptData': receiptData,
      'isSandbox': isSandbox,
      'platform': Platform.operatingSystem,
    });
  }

  Future<Map<String, dynamic>> createGatewayPayment({
    required String userId,
    required String productId,
    required String orderId,
    required double amount,
    required String currency,
    required String provider,
    Map<String, dynamic> metadata = const {},
  }) {
    return _postJson('/payments/gateway/create', {
      'userId': userId,
      'productId': productId,
      'orderId': orderId,
      'amount': amount,
      'currency': currency,
      'provider': provider,
      'metadata': metadata,
    });
  }

  Future<Map<String, dynamic>> confirmGatewayPayment({
    required String paymentIntentId,
    required String userId,
    required String orderId,
  }) {
    return _postJson('/payments/gateway/confirm', {
      'paymentIntentId': paymentIntentId,
      'userId': userId,
      'orderId': orderId,
    });
  }

  Future<Map<String, dynamic>> restorePurchases({
    required String userId,
    required String platform,
  }) {
    return _postJson('/payments/iap/restore', {
