class PaymentService extends ChangeNotifier {
  final PaymentConfig config;
  final PaymentBackendApi backendApi;
  final SecureStorage storage;

  final InAppPurchase _iap = InAppPurchase.instance;
  StreamSubscription<List<PurchaseDetails>>? _purchaseSub;

  PaymentStatus _status = PaymentStatus.idle;
  String? _message;
  String? _transactionId;
  bool _initialized = false;
  bool _iapAvailable = false;

  PaymentService({
    required this.config,
    required this.backendApi,
    required this.storage,
  });

  PaymentStatus get status => _status;
  String? get message => _message;
  String? get transactionId => _transactionId;
  bool get initialized => _initialized;
  bool get iapAvailable => _iapAvailable;

  Future<void> initialize() async {
    if (_initialized) return;
    _setState(PaymentStatus.loading, message: 'Initializing payments');
    _iapAvailable = await _iap.isAvailable();
    _purchaseSub = _iap.purchaseStream.listen(_onPurchaseUpdated, onError: (Object error) {
      _setState(PaymentStatus.failed, message: error.toString());
    });
    _initialized = true;
    _setState(PaymentStatus.idle, message: null);
  }

  Future<PaymentResult> pay(PaymentRequest request) async {
    try {
      _setState(PaymentStatus.loading, message: 'Processing payment');
      switch (request.providerType) {
        case PaymentProviderType.inAppPurchase:
          return await _processInAppPurchase(request);
        case PaymentProviderType.mobileWallet:
          return await _processWalletPayment(request);
        case PaymentProviderType.gateway:
          return await _processGatewayPayment(request);
      }
    } catch (e) {
      final msg = e is PaymentException ? e.message : e.toString();
      _setState(PaymentStatus.failed, message: msg);
      return PaymentResult.failed(msg);
    }
  }

  Future<PaymentResult> restorePurchases(String userId) async {
    try {
      if (!config.enableInAppPurchases || !_iapAvailable) {
        throw PaymentException('In-app purchases unavailable');
      }
      _setState(PaymentStatus.loading, message: 'Restoring purchases');
      await _iap.restorePurchases();
      final result = await backendApi.restorePurchases(
        userId: userId,
        platform: Platform.operatingSystem,
      );
      _setState(PaymentStatus.restored, message: 'Purchases restored');
      return PaymentResult(
        status: PaymentStatus.restored,
        message: result['message']?.toString() ?? 'Purchases restored',
        rawResponse: result,
      );
    } catch (e) {
      final msg = e is PaymentException ? e.message : e.toString();
      _setState(PaymentStatus.failed, message: msg);
      return PaymentResult.failed(msg);
    }
  }

  Future<void> disposeService() async {
    await _purchaseSub?.cancel();
    _purchaseSub = null;
    backendApi.dispose();
    _initialized = false;
  }

  Future<PaymentResult> _processInAppPurchase(PaymentRequest request) async {
    if (!config.enableInAppPurchases || !_iapAvailable) {
      throw PaymentException('In-app purchases not supported on this device');
    }

    final productDetailsResponse = await _iap.queryProductDetails({request.productId});
    if (productDetailsResponse.error != null) {
      throw PaymentException(productDetailsResponse.error!.message);
    }
    if (productDetailsResponse.productDetails.isEmpty) {
      throw PaymentException('Product not found: ${request.productId}');
    }

    final productDetails = productDetailsResponse.productDetails.first;
    final param = PurchaseParam(productDetails: productDetails);

    final completer = Completer<PaymentResult>();
    late StreamSubscription<List<PurchaseDetails>> sub;

    sub = _iap.purchaseStream.listen((purchases) async {
      for (final purchase in purchases) {
        if (purchase.productID != request.productId) continue;
        if (purchase.status == PurchaseStatus.pending) {
          _setState(PaymentStatus.pending, message: 'Purchase pending');
        } else if (purchase.status == PurchaseStatus.purchased || purchase.status == PurchaseStatus.restored) {
          final receipt = purchase.verificationData.serverVerificationData;
          final verified = await backendApi.createIapVerification(
            userId: request.userId,
            productId: request.productId,
            transactionId: purchase.purchaseID ?? purchase.verificationData.localVerificationData,
            receiptData: receipt,
            isSandbox: !config.production,
          );

          if (verified['verified'] == true) {
            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            final tx = verified['transactionId']?.toString() ?? purchase.purchaseID;
            _setState(PaymentStatus.success, transactionId: tx, message: 'Payment successful');
            if (!completer.isCompleted) {
              completer.complete(PaymentResult.success(transactionId: tx, rawResponse: verified));
            }
          } else {
            _setState(PaymentStatus.failed, message: verified['message']?.toString() ?? 'Verification failed');
            if (!completer.isCompleted) {
              completer.complete(PaymentResult.failed(verified['message']?.toString() ?? 'Verification failed', rawResponse: verified));
            }
          }
        } else if (purchase.status == PurchaseStatus.error) {
          final err = purchase.error?.message ?? 'Purchase error';
          _setState(PaymentStatus.failed, message: err);
          if (!completer.isCompleted) {
            completer.complete(PaymentResult.failed(err));
          }
        } else if (purchase.status == PurchaseStatus.canceled) {
          _setState(PaymentStatus.canceled, message: 'Purchase canceled');
          if (!completer.isCompleted) {
            completer.complete(PaymentResult.canceled());
          }
        }
      }
    });

    try {
      final started = await _iap.buyNonConsumable(purchaseParam: param);
      if (!started) {
        throw PaymentException('Unable to start in-app purchase');
      }
      return await completer.future.timeout(config.requestTimeout * 3);
    } finally {
      await sub.cancel();
    }
  }

  Future<PaymentResult> _processWalletPayment(PaymentRequest request) async {
    final provider = Platform.isIOS
        ? (config.enableApplePay ? 'apple_pay' : null)
        : (Platform.isAndroid && config.enableGooglePay ? 'google_pay' : null);

    if (provider == null) {
      throw PaymentException('Wallet payment unavailable on this platform');
    }

    final orderId = request.orderId ?? _generateOrderId();
    final gatewayInit = await backendApi.createGatewayPayment(
      userId: request.userId,
      productId: request.productId,
      orderId: orderId,
      amount: _amountFromMetadata(request.metadata),
      currency: _currencyFromMetadata(request.metadata),
      provider: provider,
      metadata: request.metadata,
    );

    final redirectUrl = gatewayInit['redirectUrl']?.toString();
    final paymentIntentId = gatewayInit['paymentIntentId']?.toString();
    if (redirectUrl == null || paymentIntentId == null) {
      throw PaymentException('Invalid gateway initialization response');
    }

    final launched = await launchUrl(Uri.parse(redirectUrl), mode: LaunchMode.externalApplication);
    if (!launched) {
      throw PaymentException('Unable to open wallet checkout');
    }

    _setState(PaymentStatus.pending, message: 'Waiting for wallet authorization');
    final confirm = await backendApi.confirmGatewayPayment(
      paymentIntentId: paymentIntentId,
      userId: request.userId,
      orderId: orderId,
    );

    if (confirm['confirmed'] == true) {
      final tx = confirm['transactionId']?.toString() ?? paymentIntentId;
      _setState(PaymentStatus.success, transactionId: tx, message: 'Wallet payment successful');
      return PaymentResult.success(transactionId: tx, rawResponse: confirm);
    }

    final message = confirm['message']?.toString() ?? 'Wallet payment failed';
    _setState(PaymentStatus.failed, message: message);
    return PaymentResult.failed(message, rawResponse: confirm);
  }

  Future<PaymentResult> _processGatewayPayment(PaymentRequest request) async {
    final orderId = request.orderId ?? _generateOrderId();
    final gatewayInit = await backendApi.createGatewayPayment(
      userId: request.userId,
      productId: request.productId,
      orderId: orderId,
      amount: _amountFromMetadata(request.metadata),
      currency: _currencyFromMetadata(request.metadata),
      provider: request.metadata['provider']?.toString() ?? 'gateway',
      metadata: request.metadata,
    );

    if (gatewayInit['requiresRedirect'] == true) {
      final redirectUrl = gatewayInit['redirectUrl']?.toString();
      if (redirectUrl == null) throw PaymentException('Missing redirect URL');
      final launched = await launchUrl(Uri.parse(redirectUrl), mode: LaunchMode.externalApplication);
      if (!launched) throw PaymentException('Unable to open checkout');
      _setState(PaymentStatus.pending, message: 'Awaiting payment confirmation');
      return PaymentResult.pending(message: 'Redirected to payment gateway');
    }

    final confirmed = gatewayInit['confirmed'] == true;
    if (confirmed) {
      final tx = gatewayInit['transactionId']?.toString() ?? gatewayInit['paymentIntentId']?.toString();
      _setState(PaymentStatus.success, transactionId: tx, message: 'Gateway payment successful');
      return PaymentResult.success(transactionId: tx, rawResponse: gatewayInit);
    }

    final msg = gatewayInit['message']?.toString() ?? 'Gateway payment initialization failed';
    _setState(PaymentStatus.failed, message: msg);
    return PaymentResult.failed(msg, rawResponse: gatewayInit);
  }

  void _onPurchaseUpdated(List<PurchaseDetails> purchases) {}

  void _setState(PaymentStatus status, {String? message, String? transactionId}) {
    _status = status;
    _message = message;
    _transactionId = transactionId;
    notifyListeners();
  }

  String _generateOrderId() => 'ord_${DateTime.now().millisecondsSinceEpoch}_${RandomId.next(8)}';

  double _amountFromMetadata(Map<String, dynamic> metadata) {
    final value = metadata['amount'];
    if (value is num) return value.toDouble();
    if (value is String) return double.tryParse(value) ?? 0.0;
    return 0.0;
  }

  String _currencyFromMetadata(Map<String, dynamic> metadata) {
    final value = metadata['currency'];
    if (value is String && value.isNotEmpty) return value.toUpperCase();
    return 'USD';
  }
}

class RandomId {
  static const String _chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  static String next(int length) {
    final sb = StringBuffer();
    final rand = DateTime.now().microsecondsSinceEpoch;
    for (int i = 0; i < length; i++) {
      sb.write(_chars[(rand + i * 17) % _chars.length]);
    }
    return sb.toString();
  }
}

class PaymentManager extends InheritedNotifier<PaymentService> {
  final PaymentService service;
  const PaymentManager({
    super.key,
    required this.service,
    required super.child,
  }) : super(notifier: service);

  static PaymentService of(BuildContext context) {
    final manager = context.dependOnInheritedWidgetOfExactType<PaymentManager>();
    assert(manager != null, 'PaymentManager not found in context');
    return manager!.service;
  }
}

class PaymentModule {
  static Future<PaymentService> create(PaymentConfig config) async {
    final storage = await SecureStorage.create();
    final backendApi = PaymentBackendApi(config);
    final service = PaymentService(
      config: config,
      backendApi: backendApi,
      storage: storage,
    );
    await service.initialize();
    return service;
  }
}

class PaymentButton extends StatefulWidget {
  final PaymentRequest request;
  final String title;
  final VoidCallback? onSuccess;
  final ValueChanged<String>? onError;

  const PaymentButton({
    super.key,
    required this.request,
    required this.title,
    this.onSuccess,
    this.onError,
  });

  @override
  State<PaymentButton> createState() => _PaymentButtonState();
}

class _PaymentButtonState extends State<PaymentButton> {
  bool _busy = false;

  @override
  Widget build(BuildContext context) {
    final service = PaymentManager.of(context);
    return ElevatedButton(
      onPressed: _busy
          ? null
          : () async {
              setState(() => _busy = true);
              final result = await service.pay(widget.request);
              if (!mounted) return;
              setState(() => _busy = false);
              if (result.status == PaymentStatus.success) {
                widget.onSuccess?.call();
              } else if (result.status == PaymentStatus.failed || result.status == PaymentStatus.canceled) {
                widget.onError?.call(result.message ?? 'Payment failed');
              }
            },
      child: Text(_busy ? 'Processing...' : widget.title),
    );
  }
}

class PaymentStatusBanner extends StatelessWidget {
  const PaymentStatusBanner({super.key});

  @override
  Widget build(BuildContext context) {
    final service = PaymentManager.of(context);
    if (service.status == PaymentStatus.idle) return const SizedBox.shrink();
    final color = switch (service.status) {
      PaymentStatus.success => Colors.green,
      PaymentStatus.failed => Colors.red,
      PaymentStatus.pending => Colors.orange,
      PaymentStatus.loading => Colors.blue,
      PaymentStatus.canceled => Colors.grey,
      PaymentStatus.restored => Colors.teal,
      PaymentStatus.idle => Colors.transparent,
    };
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      color: color.withOpacity(0.12),
      child: Text(
        service.message ?? service.status.name,
        style: TextStyle(color: color),
      ),
    );
  }
}

